package com.opengamma.strata.measure.credit;

import java.time.LocalDate;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.CurrencyAmount;
import com.opengamma.strata.collect.result.Result;
import com.opengamma.strata.pricer.common.PriceType;
import com.opengamma.strata.pricer.credit.CreditRatesProvider;
import com.opengamma.strata.pricer.credit.IsdaCdsTranchePricer;
import com.opengamma.strata.product.credit.ResolvedCdsTrancheTrade;

/**
 * Multi-scenario measure calculations for CDS tranche trades.
 * <p>
 * Each method corresponds to a measure, typically calculated by looping over
 * scenarios and calling the corresponding method in {@link IsdaCdsTranchePricer}.
 */
public class CdsTrancheMeasureCalculations {

  /**
   * Default calculations instance.
   */
  public static final CdsTrancheMeasureCalculations DEFAULT = new CdsTrancheMeasureCalculations();

  /**
   * Pricer for CDS tranches.
   */
  private final IsdaCdsTranchePricer pricer;

  /**
   * Creates an instance.
   */
  public CdsTrancheMeasureCalculations() {
    this(IsdaCdsTranchePricer.DEFAULT);
  }

  /**
   * Creates an instance with a specified pricer.
   *
   * @param pricer  the pricer
   */
  public CdsTrancheMeasureCalculations(IsdaCdsTranchePricer pricer) {
    this.pricer = pricer;
  }

  //-------------------------------------------------------------------------
  /**
   * Calculates present value for a single scenario.
   *
   * @param trade  the resolved trade
   * @param marketData  the market data
   * @param refData  the reference data
   * @return the present value
   */
  CurrencyAmount presentValue(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    CreditRatesProvider provider = marketData.creditRatesProvider();
    LocalDate valuationDate = provider.getValuationDate();
    return pricer.presentValue(trade.getProduct(), provider, valuationDate, PriceType.CLEAN, refData);
  }

  /**
   * Calculates unit price for a single scenario.
   *
   * @param trade  the resolved trade
   * @param marketData  the market data
   * @param refData  the reference data
   * @return the unit price
   */
  Double unitPrice(
      ResolvedCdsTrancheTrade trade,
      CreditRatesScenarioMarketData marketData,
      ReferenceData refData) {

    CreditRatesProvider provider = marketData.creditRatesProvider();
    LocalDate valuationDate = provider.getValuationDate();
    return pricer.price(trade.getProduct(), provider, valuationDate, PriceType.CLEAN, refData);
  }

}
